export function getRealBuildingPricesByArea(areaId: string): BuildingPrice[] {
  return REAL_BUILDING_PRICES.filter(b => b.areaId === areaId)
}

export function getRealPriceTiers(areaName: string): any[] {
  return REAL_PRICE_TIERS[areaName] || []
}

export function getRealPriceBreakdowns(areaName: string): PriceBreakdown[] {
  return REAL_PRICE_BREAKDOWNS[areaName] || []
}
